// POST /api/diagnosis - Generate diagnosis questions for a goal
export async function POST(request: NextRequest) {
  try {
    const user = await getCurrentUser()

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const body = await request.json()
    const { goalId } = body

    if (!goalId) {
      return NextResponse.json({ error: 'Goal ID is required' }, { status: 400 })
    }

    // Get goal with modules and topics
    const goal = await prisma.goal.findUnique({
      where: { id: goalId },
      include: { 
        modules: {
          include: { topics: true },
          orderBy: { order: 'asc' }
        }
      },
    })

    if (!goal) {
      return NextResponse.json({ error: 'Goal not found' }, { status: 404 })
    }

    // Flatten topics from all modules
    const allTopics = goal.modules.flatMap(m => m.topics)

    // Получаем научный контекст для более точных вопросов
    const { arxivContext } = await enrichContextWithArxiv(goal.skill, { maxPapers: 1 })
    
    // Generate questions for each topic - ПАРАЛЛЕЛЬНО для ускорения
    const topicsToProcess = allTopics.slice(0, 5) // Limit to 5 topics
    
    const questionPromises = topicsToProcess.map(async (topic) => {
      const basePrompt = getDiagnosisPrompt(goal.skill, topic.name, topic.difficulty)
      const prompt = arxivContext 
        ? `${basePrompt}\n\n[Научный контекст для создания актуальных вопросов]:\n${arxivContext}`
        : basePrompt
      
      try {
        const response = await generateCompletion(
          SYSTEM_PROMPTS.diagnosis,
          prompt,
          { json: true, temperature: 0.8 }
        )

        const question = JSON.parse(response)
        return {
          id: `${topic.id}-${Date.now()}`,
          ...question,
          topicSlug: topic.slug,
          difficulty: topic.difficulty,
        }
      } catch (e) {
        // Fallback question
        return {
          id: `${topic.id}-${Date.now()}`,
          question: `Что вы знаете о теме "${topic.name}"?`,
          type: 'multiple_choice',
          options: ['Ничего не знаю', 'Знаю основы', 'Хорошо разбираюсь', 'Эксперт'],
          correctAnswer: 2,
          explanation: 'Это вопрос для самооценки.',
          topicSlug: topic.slug,
          difficulty: topic.difficulty,
        }
      }
    })

    // Выполняем все запросы параллельно
    const questions = await Promise.all(questionPromises)

    return NextResponse.json({ questions })
  } catch (error) {
    console.error('Error generating diagnosis:', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}


// PATCH /api/diagnosis - Save diagnosis results
export async function PATCH(request: NextRequest) {
  try {
    const user = await getCurrentUser()

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const body = await request.json()
    const { goalId, results } = body // results: [{ topicSlug, score }]

    if (!goalId || !results) {
      return NextResponse.json({ error: 'Goal ID and results are required' }, { status: 400 })
    }

    // Get goal with modules and topics
    const goal = await prisma.goal.findUnique({
      where: { id: goalId },
      include: { 
        modules: {
          include: { topics: true },
          orderBy: { order: 'asc' }
        }
      },
    })

    if (!goal) {
      return NextResponse.json({ error: 'Goal not found' }, { status: 404 })
    }

    // Flatten topics from all modules
    const allTopics = goal.modules.flatMap(m => m.topics)

    // Update topic progress based on diagnosis
    for (const result of results) {
      const topic = allTopics.find((t: { slug: string }) => t.slug === result.topicSlug)
      if (!topic) continue

      const status = result.score >= 80 ? 'COMPLETED' : result.score >= 50 ? 'IN_PROGRESS' : 'AVAILABLE'
      const masteryLevel = result.score

      await prisma.topicProgress.upsert({
        where: {
          userId_topicId: { userId: user.id, topicId: topic.id },
        },
        update: {
          diagnosisScore: result.score,
          diagnosisDate: new Date(),
          masteryLevel,
          status,
        },
        create: {
          userId: user.id,
          topicId: topic.id,
          diagnosisScore: result.score,
          diagnosisDate: new Date(),
          masteryLevel,
          status,
        },
      })
    }

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Error saving diagnosis:', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { getCurrentUser } from '@/lib/auth'
import { generateWithRouter } from '@/lib/ai-router'
import { SYSTEM_PROMPTS, getCodeReviewPrompt } from '@/lib/ai/prompts'
import { addXP, updateStreak, checkAchievement, checkTaskAchievements, XP_REWARDS } from '@/lib/gamification'
import { notifyTopicCompleted } from '@/lib/services/automation'

// Обёртка для совместимости
async function generateCompletion(system: string, user: string, opts?: { json?: boolean; temperature?: number; maxTokens?: number }) {
  const result = await generateWithRouter('fast', system, user, opts)
  return result.content
}

export const dynamic = 'force-dynamic'

// POST /api/topics/[id]/submit - Submit code solution for review
export async function POST(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const user = await getCurrentUser()

    if (!user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const body = await request.json()
    const { code, lessonId, score: directScore } = body

    if (!code && directScore === undefined) {
      return NextResponse.json({ error: 'Code or score is required' }, { status: 400 })
    }

    // Get lesson and topic (не обязательно если передан directScore)
    let lesson = null
    let taskContent: any = {}

    if (lessonId) {
      lesson = await prisma.lesson.findFirst({
        where: {
          id: lessonId,
          topicId: params.id,
        },
        include: {
          topic: true,
        },
      })
      taskContent = lesson?.content as any || {}
    }

    // Если нет directScore и нет урока - ошибка
    if (directScore === undefined && !lesson) {
      return NextResponse.json({ error: 'Lesson not found' }, { status: 404 })
    }

    // Get task details from lesson content
    const taskDescription = taskContent?.description || lesson?.title || ''
    const solution = lesson?.solution || taskContent?.solution || ''

    // Review code using AI or use direct score from practice tasks
    let review: any

    // Если передан score напрямую (из практики с заданиями) - используем его
    if (directScore !== undefined) {
      const isCorrect = directScore >= 70 // 70% для прохождения
      review = {
        isCorrect,
        score: directScore,
        feedback: isCorrect ? 'Практика успешно пройдена!' : 'Попробуйте ещё раз для лучшего результата.',
        issues: [],
        suggestions: [],
        encouragement: isCorrect ? 'Отличная работа!' : 'Продолжайте практиковаться!',
      }
    } else {
      // Иначе проверяем код через AI
      try {
        const prompt = getCodeReviewPrompt(taskDescription, code, solution)
        const response = await generateCompletion(
          SYSTEM_PROMPTS.codeReview,
          prompt,
          { json: true, temperature: 0.5 }
        )
        review = JSON.parse(response)
      } catch {
        review = {
          isCorrect: false,
          score: 50,
          feedback: 'Не удалось проанализировать код. Попробуйте ещё раз.',
          issues: [],
          suggestions: [],
          encouragement: 'Продолжайте практиковаться!',
        }
      }
    }

    // Update progress
    const progress = await prisma.topicProgress.findFirst({
      where: {
        topicId: params.id,
        userId: user.id,
      },
    })

    if (progress) {
      // Сохраняем лучший результат (не перезаписываем если новый хуже)
      const bestScore = Math.max(review.score, progress.practiceScore || 0)

      // Статус COMPLETED только если лучший practiceScore >= 70%
      const newStatus = bestScore >= 70 ? 'COMPLETED' : 'IN_PROGRESS'
      // masteryLevel = среднее между теорией (если пройдена = 50) и практикой
      const theoryPart = progress.theoryCompleted ? 50 : 0
      const practicePart = Math.round(bestScore / 2) // 0-50 от практики
      const newMastery = theoryPart + practicePart

      await prisma.topicProgress.update({
        where: { id: progress.id },
        data: {
          practiceScore: bestScore,
          masteryLevel: newMastery,
          status: newStatus,
          completedAt: newStatus === 'COMPLETED' && !progress.completedAt ? new Date() : progress.completedAt,
        },
      })

      // If topic completed, unlock dependent topics
      if (newStatus === 'COMPLETED') {
        const topic = await prisma.topic.findUnique({
          where: { id: params.id },
          include: {
            module: {
              include: {
                goal: {
                  include: {
                    modules: {
                      include: { topics: true }
                    }
                  }
                }
              }
            },
          },
        })

        if (topic) {
          // Получаем данные пользователя для уведомления
          const userData = await prisma.user.findUnique({
            where: { id: user.id },
            select: { telegramId: true, name: true },
          })

          // Отправляем уведомление о завершении топика в Pipedream
          notifyTopicCompleted({
            userId: user.id,
            topicId: topic.id,
            topicName: topic.name,
            goalId: topic.module.goalId,
            goalTitle: topic.module.goal.title,
            masteryLevel: newMastery,
            practiceScore: bestScore,
            timeSpentMinutes: progress.timeSpentMinutes,
            telegramId: userData?.telegramId,
            userName: userData?.name,
          }).catch(err => console.error('[Automation] Failed to notify topic completed:', err))

          // Find topics that have this topic as prerequisite
          const dependentTopics = topic.module.goal.modules.flatMap(m => m.topics).filter((t: { prerequisiteIds: string[] }) =>
            t.prerequisiteIds.includes(topic.id)
          )

          for (const depTopic of dependentTopics) {
            // Check if all prerequisites are completed
            const prereqProgress = await prisma.topicProgress.findMany({
              where: {
                userId: user.id,
                topicId: { in: depTopic.prerequisiteIds },
              },
            })

            const allPrereqsCompleted = prereqProgress.every(
              (p: { status: string }) => p.status === 'COMPLETED' || p.status === 'MASTERED'
            )

            if (allPrereqsCompleted) {
              await prisma.topicProgress.updateMany({
                where: {
                  userId: user.id,
                  topicId: depTopic.id,
                  status: 'LOCKED',
                },
                data: { status: 'AVAILABLE' },
              })
            }
          }
        }
      }
    }

    // Update or create user stats
    const existingStats = await prisma.userStats.findUnique({
      where: { userId: user.id },
    })

    if (existingStats) {
      await prisma.userStats.update({
        where: { userId: user.id },
        data: {
          totalTasks: { increment: 1 },
          correctAnswers: review.isCorrect ? { increment: 1 } : undefined,
          lastActiveDate: new Date(),
        },
      })
    } else {
      await prisma.userStats.create({
        data: {
          userId: user.id,
          totalTasks: 1,
          correctAnswers: review.isCorrect ? 1 : 0,
          lastActiveDate: new Date(),
        },
      })
    }

    // Create review card for spaced repetition if correct
    if (review.isCorrect) {
      const topic = await prisma.topic.findUnique({
        where: { id: params.id },
      })

      if (topic) {
        await prisma.reviewCard.create({
          data: {
            userId: user.id,
            front: taskDescription,
            back: solution,
            topicSlug: topic.slug,
          },
        })
      }

      // Add XP for completing task
      const xpResult = await addXP(user.id, XP_REWARDS.COMPLETE_TASK, 'task_complete')

      // Update streak
      await updateStreak(user.id)

      // Check achievements
      await checkTaskAchievements(user.id)

      // Check first lesson achievement
      await checkAchievement(user.id, 'FIRST_LESSON')

      // Check perfect quiz achievement
      if (review.score === 100) {
        await checkAchievement(user.id, 'PERFECT_QUIZ')
      }

      // Add XP info to response
      review.xpEarned = xpResult.added
    }

    return NextResponse.json(review)
  } catch (error) {
    console.error('Error submitting code:', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

