content.text:
/**
 * Quality Gateway - Централизованная проверка качества контента
 * 
 * Единая точка входа для:
 * - Валидации теории и заданий
 * - Применения fallback при низком качестве
 * - Логирования метрик качества
 * - Принятия решения о кэшировании
 */

import { validateTheoryContent, validateTasks, type ValidationResult } from './validators/content-validator'
import { getFallbackTheory, getFallbackTasks, isFallbackContent } from './fallback-content'
import type { Domain } from './domain-prompts'

// ==================== ТИПЫ ====================

export interface QualityGatewayInput {
  content: string
  tasks: any[]
  topicName: string
  courseName: string
  domain?: Domain
}

export interface QualityMetrics {
  theoryScore: number
  tasksScore: number
  overallScore: number
  passed: boolean
  usedFallback: boolean
  theoryFallback: boolean
  tasksFallback: boolean
}

export interface QualityGatewayResult {
  content: string
  tasks: any[]
  quality: QualityMetrics
  issues: string[]
  validation: {
    theory: ValidationResult
    tasks: ValidationResult
  }
}

// ==================== КОНФИГУРАЦИЯ ====================

/**
 * Пороги качества для разных действий
 */
export const QUALITY_THRESHOLDS = {
  // Минимальный score для кэширования
  CACHE_THEORY: 50,
  CACHE_TASKS: 40,
  
  // Минимальный score для отдачи пользователю (ниже — fallback)
  SERVE_THEORY: 30,
  SERVE_TASKS: 25,
  
  // Минимальный общий score для "passed"
  OVERALL_PASS: 45
} as const

// ==================== ОСНОВНАЯ ФУНКЦИЯ ====================

/**
 * Пропускает контент через Quality Gateway
 *
 * @param input - Контент для проверки
 * @returns Проверенный контент с метриками качества
 */
export function processContentThroughGateway(input: QualityGatewayInput): QualityGatewayResult {
  const { content, tasks, topicName, courseName, domain = 'GENERAL' } = input
  const issues: string[] = []
  
  // 1. Валидация теории
  const theoryValidation = validateTheoryContent(content, domain)
  let finalContent = content
  let theoryFallback = false
  
  if (theoryValidation.score < QUALITY_THRESHOLDS.SERVE_THEORY) {
    finalContent = getFallbackTheory(topicName, courseName, domain)
    theoryFallback = true
    issues.push(`Теория заменена на fallback (score: ${theoryValidation.score})`)
  } else if (!theoryValidation.isValid) {
    issues.push(...theoryValidation.issues.map(i => `[Теория] ${i}`))
  }

  // 2. Валидация заданий
  const tasksValidation = validateTasks(tasks)
  let finalTasks = tasks
  let tasksFallback = false
  
  if (tasksValidation.score < QUALITY_THRESHOLDS.SERVE_TASKS) {
    finalTasks = getFallbackTasks(topicName, domain)
    tasksFallback = true
    issues.push(`Задания заменены на fallback (score: ${tasksValidation.score})`)
  } else if (!tasksValidation.isValid) {
    issues.push(...tasksValidation.issues.map(i => `[Задания] ${i}`))
  }

  // 3. Расчёт общего score (теория важнее — 70%)
  const overallScore = Math.round(
    (theoryValidation.score * 0.7) + (tasksValidation.score * 0.3)
  )

  // 4. Формируем метрики
  const quality: QualityMetrics = {
    theoryScore: theoryValidation.score,
    tasksScore: tasksValidation.score,
    overallScore,
    passed: overallScore >= QUALITY_THRESHOLDS.OVERALL_PASS,
    usedFallback: theoryFallback || tasksFallback,
    theoryFallback,
    tasksFallback
  }

  return {
    content: finalContent,
    tasks: finalTasks,
    quality,
    issues,
    validation: {
      theory: theoryValidation,
      tasks: tasksValidation
    }
  }
}

// ==================== ЛОГИРОВАНИЕ ====================

/**
 * Логирует метрики качества в консоль
 */
export function logQualityMetrics(
  topicName: string,
  result: QualityGatewayResult
): void {
  const { quality, issues } = result
  
  const statusEmoji = quality.passed ? '✅' : quality.usedFallback ? '⚠️' : '❌'
  
  console.log(`\n[Quality Gateway] ${statusEmoji} Topic: "${topicName}"`)
  console.log(`  Theory:  ${quality.theoryScore}/100 ${quality.theoryFallback ? '(FALLBACK)' : ''}`)
  console.log(`  Tasks:   ${quality.tasksScore}/100 ${quality.tasksFallback ? '(FALLBACK)' : ''}`)
  console.log(`  Overall: ${quality.overallScore}/100 (${quality.passed ? 'PASS' : 'FAIL'})`)
  
  if (issues.length > 0) {
    console.log(`  Issues (${issues.length}):`)
    issues.slice(0, 5).forEach(issue => console.log(`    - ${issue}`))
    if (issues.length > 5) {
      console.log(`    ... and ${issues.length - 5} more`)
    }
  }
  console.log('')
}

/**
 * Форматирует метрики для API response
 */
export function formatQualityForResponse(result: QualityGatewayResult): {
  score: number
  passed: boolean
  fallback: boolean
  issues: string[]
} {
  return {
    score: result.quality.overallScore,
    passed: result.quality.passed,
    fallback: result.quality.usedFallback,
    issues: result.issues.slice(0, 10) // Ограничиваем для response
  }
}

// ==================== УТИЛИТЫ ====================

/**
 * Проверяет, стоит ли кэшировать контент
 */
export function shouldCacheContent(result: QualityGatewayResult): {
  cacheTheory: boolean
  cacheTasks: boolean
} {
  return {
    cacheTheory: result.quality.theoryScore >= QUALITY_THRESHOLDS.CACHE_THEORY && 
                 !result.quality.theoryFallback,
    cacheTasks: result.quality.tasksScore >= QUALITY_THRESHOLDS.CACHE_TASKS && 
                !result.quality.tasksFallback
  }
}

/**
 * Быстрая проверка качества без fallback
 */
export function quickQualityCheck(content: string, tasks: any[]): {
  theoryOk: boolean
  tasksOk: boolean
  overallOk: boolean
} {
  const theoryValidation = validateTheoryContent(content)
  const tasksValidation = validateTasks(tasks)
  
  return {
    theoryOk: theoryValidation.isValid,
    tasksOk: tasksValidation.isValid,
    overallOk: theoryValidation.isValid && tasksValidation.isValid
  }
}

/**
 * Получить рекомендации по улучшению качества
 */
export function getQualityRecommendations(result: QualityGatewayResult): string[] {
  const recommendations: string[] = []
  
  if (result.quality.theoryScore < 50) {
    recommendations.push('Увеличить длину генерируемого контента (maxTokens)')
    recommendations.push('Добавить больше примеров в промпт')
  }
  
  if (result.quality.theoryScore < 70 && result.quality.theoryScore >= 50) {
    recommendations.push('Улучшить структуру контента (больше заголовков)')
  }
  
  if (result.quality.tasksScore < 50) {
    recommendations.push('Увеличить количество генерируемых заданий')
    recommendations.push('Добавить валидацию типов заданий в промпт')
  }
  
  if (result.validation.theory.issues.some(i => i.includes('повтор'))) {
    recommendations.push('Уменьшить temperature для более разнообразного контента')
  }
  
  return recommendations
}

/**
 * Content Validator - Валидация контента перед кэшированием
 * 
 * Проверяет качество сгенерированного контента:
 * - Теория: длина, структура, наличие примеров
 * - Задания: структура, типы, распределение сложности
 */

export interface ValidationResult {
  isValid: boolean
  score: number        // 0-100
  issues: string[]     // Список проблем
  suggestions: string[] // Как исправить
}

/**
 * Валидация теории перед кэшированием
 */
export function validateTheoryContent(content: string, domain?: string): ValidationResult {
  const issues: string[] = []
  const suggestions: string[] = []
  let score = 100

  // 1. Минимальная длина (2500 слов ≈ 15000 символов, но принимаем от 5000)
  if (content.length < 3000) {
    issues.push(`Слишком короткий контент: ${content.length} символов (минимум 3000)`)
    suggestions.push('Увеличить maxTokens или переформулировать промпт')
    score -= 35
  } else if (content.length < 5000) {
    issues.push(`Короткий контент: ${content.length} символов`)
    score -= 15
  }

  // 2. Наличие структуры (заголовки ##)
  const h2Count = (content.match(/^## /gm) || []).length
  const h3Count = (content.match(/^### /gm) || []).length
  
  if (h2Count < 2) {
    issues.push(`Мало секций: ${h2Count} (минимум 2)`)
    suggestions.push('Проверить шаблоны секций в domain-prompts')
    score -= 20
  }
  
  if (h2Count >= 2 && h3Count < 1) {
    issues.push('Нет подзаголовков (###)')
    score -= 5
  }

  // 3. Наличие примеров
  const hasCodeBlocks = content.includes('```')
  const hasExamples = /пример|example|например/i.test(content)
  const hasFormulas = content.includes('$') || content.includes('\\frac') || content.includes('\\sum')
  const hasLists = (content.match(/^[-*]\s/gm) || []).length >= 2
  
  if (!hasCodeBlocks && !hasExamples && !hasFormulas && !hasLists) {
    issues.push('Нет примеров, кода, формул или списков')
    suggestions.push('Добавить примеры в промпт')
    score -= 10
  }

  // 4. Проверка на "мусорный" контент
  const placeholderPatterns = [
    /раздел генерируется/i,
    /lorem ipsum/i,
    /\[placeholder\]/i,
    /контент будет добавлен/i,
    /TODO:/,
    /FIXME:/,
    /секция в разработке/i
  ]
  
  for (const pattern of placeholderPatterns) {
    if (pattern.test(content)) {
      issues.push(`Найден placeholder: ${pattern.source}`)
      score -= 25
    }
  }

  // 5. Проверка на повторения (один абзац повторяется)
  const paragraphs = content.split(/\n\n+/).filter(p => p.length > 100)
  if (paragraphs.length > 3) {
    const uniqueParagraphs = new Set(paragraphs.map(p => p.slice(0, 150).toLowerCase()))
    const uniqueRatio = uniqueParagraphs.size / paragraphs.length
    
    if (uniqueRatio < 0.6) {
      issues.push('Много повторяющегося контента')
      score -= 20
    }
  }

  // 6. Проверка языка (должен быть русский)
  const totalChars = content.replace(/\s/g, '').length
  const cyrillicChars = (content.match(/[а-яёА-ЯЁ]/g) || []).length
  const cyrillicRatio = totalChars > 0 ? cyrillicChars / totalChars : 0
  
  if (cyrillicRatio < 0.2 && totalChars > 500) {
    issues.push(`Контент преимущественно не на русском языке (${Math.round(cyrillicRatio * 100)}% кириллицы)`)
    score -= 10
  }

  // 7. Проверка на обрезанный контент
  const lastChars = content.slice(-50)
  if (lastChars.includes('...') || /[а-яa-z]$/i.test(content.trim())) {
    // Может быть обрезан, но не критично
    if (!content.trim().endsWith('.') && !content.trim().endsWith('```') && !content.trim().endsWith(':')) {
      issues.push('Контент может быть обрезан')
      score -= 5
    }
  }

  return {
    isValid: score >= 50,
    score: Math.max(0, Math.min(100, score)),
    issues,
    suggestions
  }
}

/**
 * Валидация заданий перед кэшированием
 */
export function validateTasks(tasks: unknown): ValidationResult {
  const issues: string[] = []
  const suggestions: string[] = []
  let score = 100

  // 1. Проверка что это массив
  if (!Array.isArray(tasks)) {
    return { 
      isValid: false, 
      score: 0, 
      issues: ['tasks не является массивом'], 
      suggestions: ['Проверить парсинг JSON'] 
    }
  }
  
  // 2. Минимальное количество
  if (tasks.length < 3) {
    issues.push(`Мало заданий: ${tasks.length} (минимум 3)`)
    score -= 30
  } else if (tasks.length < 5) {
    issues.push(`Недостаточно заданий: ${tasks.length} (рекомендуется 5+)`)
    score -= 10
  }

  // 3. Проверка структуры каждого задания
  const validTypes = ['single', 'multiple', 'text', 'number', 'code', 'matching']
  const validDifficulties = ['easy', 'medium', 'hard', 'expert']
  
  let invalidTasks = 0
  
  for (let i = 0; i < tasks.length; i++) {
    const task = tasks[i] as Record<string, unknown>
    let taskValid = true
    
    // Проверка вопроса
    if (!task.question || typeof task.question !== 'string' || (task.question as string).length < 5) {
      issues.push(`Задание ${i + 1}: пустой или короткий вопрос`)
      score -= 3
      taskValid = false
    }
    
    // Проверка типа
    if (!task.type || !validTypes.includes(task.type as string)) {
      issues.push(`Задание ${i + 1}: неизвестный тип "${task.type}"`)
      score -= 3
      taskValid = false
    }
    
    // Проверка вариантов для single/multiple
    if ((task.type === 'single' || task.type === 'multiple') && 
        (!Array.isArray(task.options) || (task.options as unknown[]).length < 2)) {
      issues.push(`Задание ${i + 1}: мало вариантов ответа`)
      score -= 3
      taskValid = false
    }
    
    // Проверка правильного ответа
    const hasCorrectAnswer = task.correctAnswer !== undefined || 
                             task.correctAnswers !== undefined ||
                             task.answer !== undefined
    if (!hasCorrectAnswer) {
      issues.push(`Задание ${i + 1}: нет правильного ответа`)
      score -= 5
      taskValid = false
    }
    
    if (!taskValid) invalidTasks++
  }

  // 4. Распределение сложности
  if (tasks.length >= 5) {
    const difficulties = tasks.map(t => (t as Record<string, unknown>).difficulty as string)
    const easyCount = difficulties.filter(d => d === 'easy').length
    const hardCount = difficulties.filter(d => d === 'hard' || d === 'expert').length
    
    if (easyCount === 0) {
      issues.push('Нет лёгких заданий')
      suggestions.push('Добавить easy задания в промпт')
      score -= 5
    }
    
    if (hardCount === 0) {
      issues.push('Нет сложных заданий')
      score -= 3
    }
  }

  // 5. Проверка на дубликаты вопросов
  if (tasks.length >= 3) {
    const questions = tasks.map(t => 
      ((t as Record<string, unknown>).question as string || '').toLowerCase().slice(0, 50)
    )
    const uniqueQuestions = new Set(questions.filter(q => q.length > 0))
    
    if (uniqueQuestions.size < tasks.length * 0.7) {
      issues.push('Есть дублирующиеся вопросы')
      score -= 15
    }
  }

  // 6. Слишком много невалидных заданий
  if (invalidTasks > tasks.length * 0.5) {
    issues.push(`Более половины заданий невалидны (${invalidTasks}/${tasks.length})`)
    score -= 20
  }

  return {
    isValid: score >= 40,
    score: Math.max(0, Math.min(100, score)),
    issues,
    suggestions
  }
}

